  });
}

async function saveCard(req) {
  // classification: PCI — card data never touches our DB
  const token = await stripe.tokens.create({ card: req.body.card });
  // CVV is used once for tokenization and never persisted
  await db.payments.insert({
    userId: req.user.id,
    cardToken: token.id,
    last4: token.card.last4,
  });
}

